blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie poznasz konstrukcję sprawczą <strong>have / get something done</strong>. Używamy jej, gdy ktoś inny wykonuje czynność za nas, zwykle jako usługę albo na naszą prośbę.",
    "rules": [
        {
            "label": "have + object + V3",
            "color": "emerald",
            "text": "To neutralna, często nieco bardziej formalna konstrukcja sprawcza.",
            "example": "I had my car repaired. — Naprawiono mi samochód."
        },
        {
            "label": "get + object + V3",
            "color": "blue",
            "text": "Ta wersja jest bardziej potoczna, ale znaczenie pozostaje bardzo podobne.",
            "example": "I got my hair cut. — Ściąłem włosy u fryzjera."
        },
        {
            "label": "Najważniejsza idea",
            "color": "amber",
            "text": "To <strong>ktoś inny</strong> wykonuje czynność, a my jesteśmy odbiorcą usługi albo skutku.",
            "example": "I don't cut my hair myself — a hairdresser does it."
        }
    ]
}

{
    "title": "1. Konstrukcja sprawcza, strona czynna i bierna",
    "intro": "Porównanie trzech sposobów mówienia o tej samej sytuacji:",
    "rows": [
        {
            "en": "Active: I repaired my car.",
            "ua": "Sam naprawiłem samochód.",
            "note": "To ja wykonałem tę czynność."
        },
        {
            "en": "Passive: My car was repaired.",
            "ua": "Samochód został naprawiony.",
            "note": "Liczy się rezultat, a nie wykonawca."
        },
        {
            "en": "Causative: I had my car repaired.",
            "ua": "Naprawiono mi samochód.",
            "note": "Zleciłem tę usługę komuś innemu."
        }
    ],
    "warning": "📌 Konstrukcja sprawcza pokazuje, że nie wykonujemy czynności sami, tylko organizujemy, żeby zrobił ją ktoś inny."
}

{
    "title": "2. Have something done w różnych czasach",
    "intro": "Zmienia się czasownik <strong>have</strong>, a reszta konstrukcji pozostaje taka sama:",
    "items": [
        {
            "label": "Present Simple",
            "title": "have / has + object + V3",
            "subtitle": "I have my hair cut every month."
        },
        {
            "label": "Past Simple",
            "title": "had + object + V3",
            "subtitle": "She had her car serviced yesterday."
        },
        {
            "label": "Future Simple",
            "title": "will have + object + V3",
            "subtitle": "I will have my suit cleaned tomorrow."
        },
        {
            "label": "Present Perfect",
            "title": "have / has had + object + V3",
            "subtitle": "We have had our house painted."
        },
        {
            "label": "Present Continuous",
            "title": "am / is / are having + object + V3",
            "subtitle": "They are having their kitchen renovated."
        },
        {
            "label": "Modal verbs",
            "title": "modal + have + object + V3",
            "subtitle": "You should have your eyes tested."
        }
    ]
}

{
    "title": "3. Typowe sytuacje dla sprawcy",
    "sections": [
        {
            "label": "Usługi / usługa",
            "color": "emerald",
            "description": "Kiedy <strong>zamawiamy usługę</strong>:",
            "examples": [
                {
                    "en": "I had my hair cut yesterday.",
                    "ua": "Wczoraj ścięłam włosy."
                },
                {
                    "en": "She has her nails done every week.",
                    "ua": "Co tydzień robi sobie manicure."
                },
                {
                    "en": "We had the house painted last month.",
                    "ua": "W zeszłym miesiącu malowaliśmy nasz dom."
                }
            ]
        },
        {
            "label": "Naprawa/konserwacja",
            "color": "blue",
            "description": "W przypadku <strong>naprawy i konserwacji</strong>:",
            "examples": [
                {
                    "en": "I need to have my car serviced.",
                    "ua": "Muszę oddać samochód do przeglądu."
                },
                {
                    "en": "They had their roof repaired.",
                    "ua": "Naprawiono ich dach."
                },
                {
                    "en": "You should have your brakes checked.",
                    "ua": "Powinieneś sprawdzić hamulce."
                }
            ]
        },
        {
            "label": "Usługi medyczne",
            "color": "amber",
            "description": "W przypadku procedur <strong>medycznych</strong>:",
            "examples": [
                {
                    "en": "I had my eyes tested last week.",
                    "ua": "W zeszłym tygodniu sprawdzałem wzrok."
                },
                {
                    "en": "She needs to have her teeth cleaned.",
                    "ua": "Musi umyć zęby (u dentysty)."
                },
                {
                    "en": "He had his blood pressure checked.",
                    "ua": "Zmierzono mu ciśnienie krwi."
                }
            ]
        },
        {
            "label": "Dostawa/montaż",
            "color": "rose",
            "description": "W przypadku <strong>dostawy i instalacji</strong>:",
            "examples": [
                {
                    "en": "We had a new kitchen installed.",
                    "ua": "Zamontowano dla nas nową kuchnię."
                },
                {
                    "en": "They had the furniture delivered.",
                    "ua": "Dostarczono im meble."
                },
                {
                    "en": "I had the internet connected yesterday.",
                    "ua": "Wczoraj miałem połączenie z internetem."
                }
            ]
        }
    ]
}

{
    "title": "4. Have something done i get something done",
    "intro": "Obie konstrukcje znaczą prawie to samo, ale różnią się stylem:",
    "rows": [
        {
            "en": "Have: I had my car repaired.",
            "ua": "Naprawiono mi samochód.",
            "note": "Brzmi neutralnie i trochę bardziej formalnie."
        },
        {
            "en": "Get: I got my car repaired.",
            "ua": "Naprawiono mi samochód.",
            "note": "Bardziej potoczne; często sugeruje, że udało się to zorganizować."
        },
        {
            "en": "Have: She had her dress made.",
            "ua": "Uszyto jej sukienkę.",
            "note": "Neutralny opis zamówionej usługi."
        },
        {
            "en": "Get: She finally got her dress made.",
            "ua": "W końcu uszyto jej sukienkę.",
            "note": "Często podkreśla wysiłek albo trudność."
        }
    ],
    "warning": "📌 <strong>Get</strong> brzmi bardziej potocznie i może podkreślać, że po pewnym wysiłku wreszcie udało się coś załatwić."
}

{
    "title": "5. Nieprzyjemne zdarzenia",
    "sections": [
        {
            "label": "Niechciane sytuacje",
            "color": "rose",
            "description": "Konstrukcji sprawczej używamy też przy <strong>nieprzyjemnych wydarzeniach</strong>, które nas spotkały.",
            "examples": [
                {
                    "en": "I had my wallet stolen.",
                    "ua": "Ukradziono mi portfel."
                },
                {
                    "en": "She had her car broken into.",
                    "ua": "Włamano się do jej samochodu."
                },
                {
                    "en": "They had their house burgled.",
                    "ua": "Okradziono ich dom."
                }
            ]
        },
        {
            "label": "Znaczenie zależy od kontekstu",
            "color": "amber",
            "description": "Ten sam wzór może mówić o <strong>usłudze</strong> albo o <strong>nieprzyjemnym zdarzeniu</strong>. O wszystkim decyduje kontekst.",
            "examples": [
                {
                    "en": "I had my hair cut.",
                    "ua": "Ściąłem włosy u fryzjera."
                },
                {
                    "en": "I had my bag stolen.",
                    "ua": "Ukradziono mi torbę."
                },
                {
                    "en": "She had her phone repaired.",
                    "ua": "Naprawiono jej telefon."
                }
            ]
        }
    ]
}

{
    "title": "6. Przeczenia i pytania",
    "intro": "Tak tworzymy przeczenia i pytania w konstrukcji sprawczej:",
    "items": [
        {
            "label": "Przeczenie z have",
            "title": "do / does / did not have + object + V3",
            "subtitle": "I didn't have my car repaired."
        },
        {
            "label": "Przeczenie z get",
            "title": "do / does / did not get + object + V3",
            "subtitle": "She didn't get her hair cut."
        },
        {
            "label": "Pytanie z have",
            "title": "Do / Does / Did + subject + have + object + V3?",
            "subtitle": "Did you have your car serviced?"
        },
        {
            "label": "Pytanie z get",
            "title": "Do / Does / Did + subject + get + object + V3?",
            "subtitle": "Did she get her dress made?"
        },
        {
            "label": "Pytanie z wh-",
            "title": "Wh-word + do / does / did + subject + have / get + object + V3?",
            "subtitle": "Where did you get your hair cut?"
        },
        {
            "label": "Future",
            "title": "Will + subject + have / get + object + V3?",
            "subtitle": "Will you have the report checked tomorrow?"
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Użycie bezokolicznika zamiast V3.",
            "wrong": "I had my car to repair.",
            "right": "✅ I had my car repaired."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Wstawienie obiektu w złe miejsce.",
            "wrong": "I had repaired my car.",
            "right": "✅ I had my car repaired."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie konstrukcji sprawczej z formą czynną.",
            "wrong": "I had cut my hair. (to znaczy: sam obciąłem sobie włosy)",
            "right": "✅ I had my hair cut. (ktoś obciął mi włosy)"
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowy szyk.",
            "wrong": "I had repaired my car yesterday.",
            "right": "✅ I had my car repaired yesterday."
        }
    ]
}
